-- ═══════════════════════════════════════════════════════════════
-- Synchronisation minimas_convention — Excel minimas-sociaux.xlsx
-- Salaires minima bruts au 1er juillet 2025 (SMIC 2026)
-- ═══════════════════════════════════════════════════════════════

-- ÉTAPE 1 : Supprimer les doublons existants (garder 1 seul par clé)
DELETE FROM minimas_convention a
  USING minimas_convention b
  WHERE a.id > b.id
    AND a.poste = b.poste
    AND a.type_oeuvre = b.type_oeuvre
    AND a.is_specialise = b.is_specialise
    AND a.unite = b.unite;

-- ÉTAPE 2 : Créer l'index unique (maintenant sans doublons)
CREATE UNIQUE INDEX IF NOT EXISTS idx_minimas_convention_unique
  ON minimas_convention (poste, type_oeuvre, is_specialise, unite);

-- ÉTAPE 3 : Upsert de toutes les entrées (1624 lignes)

-- Vérification
SELECT type_oeuvre, count(*) FROM minimas_convention GROUP BY type_oeuvre ORDER BY type_oeuvre;